  const getWindingOffset = (index: number) => {
    const cycle = index % 4;
    switch (cycle) {
      case 0: return '0%';
      case 1: return '25%';
      case 2: return '0%';
      case 3: return '-25%';
      default: return '0%';
    }
  };

