                      strokeDashoffset={100 - (mastery / 10)}
                      strokeLinecap="round"
                      style={{ transition: 'stroke-dashoffset 1s ease-out' }}
                    />
                  </svg>
                )}
              </motion.button>

              <div style={{ 
                marginTop: '12px', 
                textAlign: 'center', 
                width: '120px',
                opacity: isLocked ? 0.4 : 1
              }}>
                <div style={{ 
                  fontSize: '0.65rem', 
                  fontWeight: 900, 
